═════════════════════════════════ */
  .slide-8 {
    background: linear-gradient(160deg, #0f172a 0%, #1a2332 50%, #0f172a 100%);
  }
  .slide-8 .slide-label { color: var(--accent-amber); }
  .slide-8 .takeaway-list {
    display: flex;
    flex-direction: column;
    gap: 32px;
    flex: 1;
    justify-content: center;
    padding: 16px 0;
  }
  .slide-8 .takeaway-item {
    display: flex;
    gap: 20px;
    align-items: flex-start;
  }
  .slide-8 .takeaway-item .tk-icon { font-size: 32px; flex-shrink: 0; margin-top: 2px; }
  .slide-8 .takeaway-item h3 { font-size: 24px; font-weight: 700; color: var(--text-primary); margin-bottom: 6px; }
  .slide-8 .takeaway-item p { font-size: 21px; font-weight: 400; color: var(--text-secondary); line-height: 1.5; }

  .slide-8 .cta-divider {
    border: none;
    border-top: 1px solid var(--border);
    margin: 12px 0 20px;
  }
  .slide-8 .cta { text-align: center; }
  .slide-8 .cta p { font-size: 24px; font-weight: 600; color: var(--text-secondary); line-height: 1.5; }
  .slide-8 .cta .small { font-size: 20px; font-weight: 500; color: var(--text-muted); margin-top: 8px; }

  /* ════════════════════════════════════════════════════ */
  /* SLIDE: THE GAP (inserted after slide 2)            */
  /* ════════════════════════════════════════════════════ */
  .slide-gap { background: var(--bg-dark); }
  .slide-gap .slide-label { color: var(--accent-cyan); }
